     1→export class DateHelpers {
     2→	static formatDate(date: Date): string {
     3→		return date.toISOString().split('T')[0] ?? '';
     4→	}
     5→
     6→	static parseDate(dateString: string): Date {
     7→		return new Date(dateString);
     8→	}
     9→
    10→	static addDays(date: Date, days: number): Date {
    11→		const result = new Date(date);
    12→		result.setDate(result.getDate() + days);
    13→		return result;
    14→	}
    15→
    16→	static daysBetween(startDate: Date, endDate: Date): number {
    17→		const timeDifference = endDate.getTime() - startDate.getTime();
    18→		return Math.ceil(timeDifference / (1000 * 3600 * 24));
    19→	}
    20→
    21→	static generateDateSequence(startDate: Date, endDate: Date): string[] {
    22→		const dates: string[] = [];
    23→		const currentDate = new Date(startDate);
    24→
    25→		while (currentDate <= endDate) {
    26→			dates.push(this.formatDate(currentDate));
    27→			currentDate.setDate(currentDate.getDate() + 1);
    28→		}
    29→
    30→		return dates;
    31→	}
    32→
    33→	static fillMissingDates(
    34→		data: { date: string; value: number }[],
    35→	): { date: string; value: number }[] {
    36→		if (data.length === 0) return [];
    37→
    38→		const sortedData = data.sort(
    39→			(a, b) => new Date(a.date).getTime() - new Date(b.date).getTime(),
    40→		);
    41→		const firstItem = sortedData[0];
    42→		const lastItem = sortedData[sortedData.length - 1];
    43→		if (!firstItem || !lastItem) return [];
    44→
    45→		const startDate = new Date(firstItem.date);
    46→		const endDate = new Date(lastItem.date);
    47→
    48→		const allDates = this.generateDateSequence(startDate, endDate);
    49→		const dataMap = new Map(data.map((item) => [item.date, item.value]));
    50→
    51→		return allDates.map((date) => ({
    52→			date,
    53→			value: dataMap.get(date) ?? 0,
    54→		}));
    55→	}
    56→
    57→	static getWeekday(date: Date): number {
    58→		return date.getDay();
    59→	}
    60→
    61→	static getWeekOfYear(date: Date): number {
    62→		const start = new Date(date.getFullYear(), 0, 1);
    63→		const diff = date.getTime() - start.getTime();
    64→		const oneWeek = 1000 * 60 * 60 * 24 * 7;
    65→		return Math.floor(diff / oneWeek) + 1;
    66→	}
    67→
    68→	static getDayOfYear(date: Date): number {
    69→		const start = new Date(date.getFullYear(), 0, 1);
    70→		const diff = date.getTime() - start.getTime();
    71→		const oneDay = 1000 * 60 * 60 * 24;
    72→		return Math.floor(diff / oneDay) + 1;
    73→	}
    74→
    75→	static isWeekend(date: Date): boolean {
    76→		const day = date.getDay();
    77→		return day === 0 || day === 6;
    78→	}
    79→
    80→	static getQuarter(date: Date): number {
    81→		return Math.floor((date.getMonth() + 3) / 3);
    82→	}
    83→
    84→	static isHoliday(
    85→		date: Date,
    86→		holidays: { date: string; effect_window: number }[],
    87→	): boolean {
    88→		return holidays.some((holiday) => {
    89→			const holidayDate = new Date(holiday.date);
    90→			const daysDiff = Math.abs(this.daysBetween(date, holidayDate));
    91→			return daysDiff <= holiday.effect_window / 2;
    92→		});
    93→	}
    94→
    95→	static getHolidayEffect(
    96→		date: Date,
    97→		holidays: { date: string; effect_window: number; impact_multiplier: number }[],
    98→	): number {
    99→		let maxEffect = 1.0;
   100→
   101→		holidays.forEach((holiday) => {
   102→			const holidayDate = new Date(holiday.date);
   103→			const daysDiff = Math.abs(this.daysBetween(date, holidayDate));
   104→
   105→			if (daysDiff <= holiday.effect_window / 2) {
   106→				const effectStrength = 1 - daysDiff / (holiday.effect_window / 2);
   107→				const effect = 1 + (holiday.impact_multiplier - 1) * effectStrength;
   108→				maxEffect = Math.max(maxEffect, effect);
   109→			}
   110→		});
   111→
   112→		return maxEffect;
   113→	}
   114→
   115→	static getSeasonalIndex(date: Date, period: 'weekly' | 'monthly' | 'yearly'): number {
   116→		switch (period) {
   117→			case 'weekly':
   118→				return this.getWeekday(date);
   119→			case 'monthly':
   120→				return date.getDate() - 1;
   121→			case 'yearly':
   122→				return this.getDayOfYear(date) - 1;
   123→			default:
   124→				return 0;
   125→		}
   126→	}
   127→
   128→	static isSameWeek(date1: Date, date2: Date): boolean {
   129→		const week1 = this.getWeekOfYear(date1);
   130→		const week2 = this.getWeekOfYear(date2);
   131→		return week1 === week2 && date1.getFullYear() === date2.getFullYear();
   132→	}
   133→
   134→	static getMonthName(date: Date): string {
   135→		const months = [
   136→			'January',
   137→			'February',
   138→			'March',
   139→			'April',
   140→			'May',
   141→			'June',
   142→			'July',
   143→			'August',
   144→			'September',
   145→			'October',
   146→			'November',
   147→			'December',
   148→		];
   149→		return months[date.getMonth()] ?? 'Unknown';
   150→	}
   151→
   152→	static getNextWeekDates(date: Date = new Date()): string[] {
   153→		const tomorrow = this.addDays(date, 1);
   154→		const dates: string[] = [];
   155→
   156→		for (let i = 0; i < 7; i++) {
   157→			dates.push(this.formatDate(this.addDays(tomorrow, i)));
   158→		}
   159→
   160→		return dates;
   161→	}
   162→}
