export class DateHelpers {
	static formatDate({ date }: { date: Date }): string {
		return date.toISOString().split('T')[0] ?? '';
	}

	static parseDate({ dateString }: { dateString: string }): Date {
		return new Date(dateString);
	}

	static addDays({ date, days }: { date: Date; days: number }): Date {
		const result = new Date(date);
		result.setDate(result.getDate() + days);
		return result;
	}

	static daysBetween({ startDate, endDate }: { startDate: Date; endDate: Date }): number {
		const timeDifference = endDate.getTime() - startDate.getTime();
		return Math.ceil(timeDifference / (1000 * 3600 * 24));
	}

	static generateDateSequence({
		startDate,
		endDate,
	}: {
		startDate: Date;
		endDate: Date;
	}): string[] {
		const dates: string[] = [];
		const currentDate = new Date(startDate);

		while (currentDate <= endDate) {
			dates.push(this.formatDate({ date: currentDate }));
			currentDate.setDate(currentDate.getDate() + 1);
		}

		return dates;
	}

	static fillMissingDates({
		data,
	}: {
		data: { date: string; value: number }[];
	}): { date: string; value: number }[] {
		if (data.length === 0) return [];

		const sortedData = data.sort(
			(a, b) => new Date(a.date).getTime() - new Date(b.date).getTime(),
		);
		const firstItem = sortedData[0];
		const lastItem = sortedData[sortedData.length - 1];
		if (!firstItem || !lastItem) return [];

		const startDate = new Date(firstItem.date);
		const endDate = new Date(lastItem.date);

		const allDates = this.generateDateSequence({ startDate, endDate });
		const dataMap = new Map(data.map((item) => [item.date, item.value]));

		return allDates.map((date) => ({
			date,
			value: dataMap.get(date) ?? 0,
		}));
	}

	static getWeekday({ date }: { date: Date }): number {
		return date.getDay();
	}

	static getWeekOfYear({ date }: { date: Date }): number {
		const start = new Date(date.getFullYear(), 0, 1);
		const diff = date.getTime() - start.getTime();
		const oneWeek = 1000 * 60 * 60 * 24 * 7;
		return Math.floor(diff / oneWeek) + 1;
	}

	static getDayOfYear({ date }: { date: Date }): number {
		const start = new Date(date.getFullYear(), 0, 1);
		const diff = date.getTime() - start.getTime();
		const oneDay = 1000 * 60 * 60 * 24;
		return Math.floor(diff / oneDay) + 1;
	}

	static isWeekend({ date }: { date: Date }): boolean {
		const day = date.getDay();
		return day === 0 || day === 6;
	}

	static getQuarter({ date }: { date: Date }): number {
		return Math.floor((date.getMonth() + 3) / 3);
	}

	static isHoliday({
		date,
		holidays,
	}: {
		date: Date;
		holidays: { date: string; effect_window: number }[];
	}): boolean {
		return holidays.some((holiday) => {
			const holidayDate = new Date(holiday.date);
			const daysDiff = Math.abs(this.daysBetween({ startDate: date, endDate: holidayDate }));
			return daysDiff <= holiday.effect_window / 2;
		});
	}

	static getHolidayEffect({
		date,
		holidays,
	}: {
		date: Date;
		holidays: { date: string; effect_window: number; impact_multiplier: number }[];
	}): number {
		let maxEffect = 1.0;

		holidays.forEach((holiday) => {
			const holidayDate = new Date(holiday.date);
			const daysDiff = Math.abs(this.daysBetween({ startDate: date, endDate: holidayDate }));

			if (daysDiff <= holiday.effect_window / 2) {
				const effectStrength = 1 - daysDiff / (holiday.effect_window / 2);
				const effect = 1 + (holiday.impact_multiplier - 1) * effectStrength;
				maxEffect = Math.max(maxEffect, effect);
			}
		});

		return maxEffect;
	}

	static getSeasonalIndex({
		date,
		period,
	}: {
		date: Date;
		period: 'weekly' | 'monthly' | 'yearly';
	}): number {
		switch (period) {
			case 'weekly':
				return this.getWeekday({ date });
			case 'monthly':
				return date.getDate() - 1;
			case 'yearly':
				return this.getDayOfYear({ date }) - 1;
			default:
				return 0;
		}
	}

	static isSameWeek({ date1, date2 }: { date1: Date; date2: Date }): boolean {
		const week1 = this.getWeekOfYear({ date: date1 });
		const week2 = this.getWeekOfYear({ date: date2 });
		return week1 === week2 && date1.getFullYear() === date2.getFullYear();
	}

	static getMonthName({ date }: { date: Date }): string {
		const months = [
			'January',
			'February',
			'March',
			'April',
			'May',
			'June',
			'July',
			'August',
			'September',
			'October',
			'November',
			'December',
		];
		return months[date.getMonth()] ?? 'Unknown';
	}

	static getNextWeekDates(date: Date = new Date()): string[] {
		const tomorrow = this.addDays({ date, days: 1 });
		const dates: string[] = [];

		for (let i = 0; i < 7; i++) {
			dates.push(this.formatDate({ date: this.addDays({ date: tomorrow, days: i }) }));
		}

		return dates;
	}
}

