import { DateHelpers } from '@utils/date-helpers.util';

describe('DateHelpers', () => {
	describe('formatDate', () => {
		it('should format a date to ISO string date part', () => {
			const date = new Date('2024-06-15T12:00:00Z');
			const result = DateHelpers.formatDate({ date });
			expect(result).toBe('2024-06-15');
		});

		it('should format January 1st correctly', () => {
			const date = new Date('2024-01-01T00:00:00Z');
			const result = DateHelpers.formatDate({ date });
			expect(result).toBe('2024-01-01');
		});
	});

	describe('parseDate', () => {
		it('should parse a date string into a Date object', () => {
			const result = DateHelpers.parseDate({ dateString: '2024-06-15' });
			expect(result).toBeInstanceOf(Date);
			expect(result.toISOString().startsWith('2024-06-15')).toBe(true);
		});

		it('should handle invalid date strings', () => {
			const result = DateHelpers.parseDate({ dateString: 'invalid' });
			expect(isNaN(result.getTime())).toBe(true);
		});
	});

	describe('addDays', () => {
		it('should add positive days to a date', () => {
			const date = new Date(2024, 0, 1);
			const result = DateHelpers.addDays({ date, days: 5 });
			expect(result.getDate()).toBe(6);
		});

		it('should subtract days when negative value is provided', () => {
			const date = new Date(2024, 0, 10);
			const result = DateHelpers.addDays({ date, days: -3 });
			expect(result.getDate()).toBe(7);
		});

		it('should not mutate the original date', () => {
			const date = new Date(2024, 0, 1);
			DateHelpers.addDays({ date, days: 10 });
			expect(date.getDate()).toBe(1);
		});
	});

	describe('daysBetween', () => {
		it('should calculate days between two dates', () => {
			const startDate = new Date(2024, 0, 1);
			const endDate = new Date(2024, 0, 11);
			const result = DateHelpers.daysBetween({ startDate, endDate });
			expect(result).toBe(10);
		});

		it('should return negative value when end is before start', () => {
			const startDate = new Date(2024, 0, 11);
			const endDate = new Date(2024, 0, 1);
			const result = DateHelpers.daysBetween({ startDate, endDate });
			expect(result).toBeLessThan(0);
		});

		it('should return 0 for same date', () => {
			const date = new Date(2024, 0, 1);
			const result = DateHelpers.daysBetween({ startDate: date, endDate: date });
			expect(result).toBe(0);
		});
	});

	describe('generateDateSequence', () => {
		it('should generate a sequence of dates between start and end', () => {
			const startDate = new Date(2024, 0, 1);
			const endDate = new Date(2024, 0, 3);
			const result = DateHelpers.generateDateSequence({ startDate, endDate });
			expect(result).toHaveLength(3);
		});

		it('should return a single date when start equals end', () => {
			const date = new Date('2024-06-15T12:00:00Z');
			const result = DateHelpers.generateDateSequence({ startDate: date, endDate: date });
			expect(result).toHaveLength(1);
		});

		it('should return empty array when start is after end', () => {
			const startDate = new Date(2024, 0, 10);
			const endDate = new Date(2024, 0, 1);
			const result = DateHelpers.generateDateSequence({ startDate, endDate });
			expect(result).toHaveLength(0);
		});
	});

	describe('fillMissingDates', () => {
		it('should fill missing dates with zero values', () => {
			const data = [
				{ date: '2024-01-01', value: 10 },
				{ date: '2024-01-03', value: 20 },
			];
			const result = DateHelpers.fillMissingDates({ data });
			expect(result).toHaveLength(3);
			const missingDay = result.find((d) => d.date === '2024-01-02');
			expect(missingDay?.value).toBe(0);
		});

		it('should return empty array for empty input', () => {
			const result = DateHelpers.fillMissingDates({ data: [] });
			expect(result).toEqual([]);
		});

		it('should handle single element array', () => {
			const data = [{ date: '2024-01-01', value: 5 }];
			const result = DateHelpers.fillMissingDates({ data });
			expect(result).toHaveLength(1);
			expect(result[0]?.value).toBe(5);
		});

		it('should preserve existing values', () => {
			const data = [
				{ date: '2024-01-01', value: 10 },
				{ date: '2024-01-02', value: 20 },
			];
			const result = DateHelpers.fillMissingDates({ data });
			const day1 = result.find((d) => d.date === '2024-01-01');
			expect(day1?.value).toBe(10);
		});
	});

	describe('getWeekday', () => {
		it('should return the weekday number for a date', () => {
			const date = new Date(2024, 0, 1);
			const result = DateHelpers.getWeekday({ date });
			expect(result).toBeGreaterThanOrEqual(0);
			expect(result).toBeLessThanOrEqual(6);
		});

		it('should return 1 for Monday', () => {
			const monday = new Date(2024, 0, 1);
			const result = DateHelpers.getWeekday({ date: monday });
			expect(result).toBe(1);
		});
	});

	describe('getWeekOfYear', () => {
		it('should return week 1 for January 1st', () => {
			const date = new Date(2024, 0, 1);
			const result = DateHelpers.getWeekOfYear({ date });
			expect(result).toBe(1);
		});

		it('should return a higher week number for later dates', () => {
			const earlyDate = new Date(2024, 0, 1);
			const laterDate = new Date(2024, 5, 1);
			const earlyWeek = DateHelpers.getWeekOfYear({ date: earlyDate });
			const laterWeek = DateHelpers.getWeekOfYear({ date: laterDate });
			expect(laterWeek).toBeGreaterThan(earlyWeek);
		});
	});

	describe('getDayOfYear', () => {
		it('should return 1 for January 1st', () => {
			const date = new Date(2024, 0, 1);
			const result = DateHelpers.getDayOfYear({ date });
			expect(result).toBe(1);
		});

		it('should return 32 for February 1st', () => {
			const date = new Date(2024, 1, 1);
			const result = DateHelpers.getDayOfYear({ date });
			expect(result).toBe(32);
		});
	});

	describe('isWeekend', () => {
		it('should return true for Saturday', () => {
			const saturday = new Date(2024, 0, 6);
			expect(DateHelpers.isWeekend({ date: saturday })).toBe(true);
		});

		it('should return true for Sunday', () => {
			const sunday = new Date(2024, 0, 7);
			expect(DateHelpers.isWeekend({ date: sunday })).toBe(true);
		});

		it('should return false for weekdays', () => {
			const monday = new Date(2024, 0, 1);
			expect(DateHelpers.isWeekend({ date: monday })).toBe(false);
		});
	});

	describe('getQuarter', () => {
		it('should return Q1 for January', () => {
			const date = new Date(2024, 0, 15);
			expect(DateHelpers.getQuarter({ date })).toBe(1);
		});

		it('should return Q2 for April', () => {
			const date = new Date(2024, 3, 15);
			expect(DateHelpers.getQuarter({ date })).toBe(2);
		});

		it('should return Q3 for July', () => {
			const date = new Date(2024, 6, 15);
			expect(DateHelpers.getQuarter({ date })).toBe(3);
		});

		it('should return Q4 for October', () => {
			const date = new Date(2024, 9, 15);
			expect(DateHelpers.getQuarter({ date })).toBe(4);
		});
	});

	describe('isHoliday', () => {
		it('should return true when date is within holiday window', () => {
			const date = new Date(2024, 11, 25);
			const holidays = [{ date: '2024-12-25', effect_window: 4 }];
			expect(DateHelpers.isHoliday({ date, holidays })).toBe(true);
		});

		it('should return false when date is outside holiday window', () => {
			const date = new Date(2024, 0, 1);
			const holidays = [{ date: '2024-12-25', effect_window: 2 }];
			expect(DateHelpers.isHoliday({ date, holidays })).toBe(false);
		});

		it('should return false for empty holidays array', () => {
			const date = new Date(2024, 11, 25);
			expect(DateHelpers.isHoliday({ date, holidays: [] })).toBe(false);
		});
	});

	describe('getHolidayEffect', () => {
		it('should return 1.0 when no holidays are nearby', () => {
			const date = new Date(2024, 0, 1);
			const holidays = [{ date: '2024-12-25', effect_window: 2, impact_multiplier: 2.0 }];
			const result = DateHelpers.getHolidayEffect({ date, holidays });
			expect(result).toBe(1.0);
		});

		it('should return multiplied effect when date is on holiday', () => {
			const date = new Date(2024, 11, 25);
			const holidays = [{ date: '2024-12-25', effect_window: 4, impact_multiplier: 2.0 }];
			const result = DateHelpers.getHolidayEffect({ date, holidays });
			expect(result).toBeGreaterThan(1.0);
		});

		it('should return 1.0 for empty holidays array', () => {
			const date = new Date(2024, 11, 25);
			const result = DateHelpers.getHolidayEffect({ date, holidays: [] });
			expect(result).toBe(1.0);
		});
	});

	describe('getSeasonalIndex', () => {
		it('should return weekday index for weekly period', () => {
			const date = new Date(2024, 0, 1);
			const result = DateHelpers.getSeasonalIndex({ date, period: 'weekly' });
			expect(result).toBe(DateHelpers.getWeekday({ date }));
		});

		it('should return day of month minus 1 for monthly period', () => {
			const date = new Date(2024, 0, 15);
			const result = DateHelpers.getSeasonalIndex({ date, period: 'monthly' });
			expect(result).toBe(14);
		});

		it('should return day of year minus 1 for yearly period', () => {
			const date = new Date(2024, 0, 1);
			const result = DateHelpers.getSeasonalIndex({ date, period: 'yearly' });
			expect(result).toBe(0);
		});

		it('should return 0 for default case', () => {
			const date = new Date(2024, 0, 1);
			const result = DateHelpers.getSeasonalIndex({
				date,
				period: 'daily' as 'weekly' | 'monthly' | 'yearly',
			});
			expect(result).toBe(0);
		});
	});

	describe('isSameWeek', () => {
		it('should return true for dates in the same week', () => {
			const date1 = new Date(2024, 0, 1);
			const date2 = new Date(2024, 0, 5);
			const result = DateHelpers.isSameWeek({ date1, date2 });
			expect(result).toBe(true);
		});

		it('should return false for dates in different weeks', () => {
			const date1 = new Date(2024, 0, 1);
			const date2 = new Date(2024, 0, 15);
			const result = DateHelpers.isSameWeek({ date1, date2 });
			expect(result).toBe(false);
		});

		it('should return false for same week but different years', () => {
			const date1 = new Date(2023, 11, 31);
			const date2 = new Date(2024, 0, 1);
			const result = DateHelpers.isSameWeek({ date1, date2 });
			expect(result).toBe(false);
		});
	});

	describe('getMonthName', () => {
		it('should return January for month 0', () => {
			const date = new Date(2024, 0, 1);
			expect(DateHelpers.getMonthName({ date })).toBe('January');
		});

		it('should return December for month 11', () => {
			const date = new Date(2024, 11, 1);
			expect(DateHelpers.getMonthName({ date })).toBe('December');
		});

		it('should return June for month 5', () => {
			const date = new Date(2024, 5, 1);
			expect(DateHelpers.getMonthName({ date })).toBe('June');
		});
	});

	describe('getNextWeekDates', () => {
		it('should return exactly 7 dates', () => {
			const result = DateHelpers.getNextWeekDates();
			expect(result).toHaveLength(7);
		});

		it('should start from the day after the provided date', () => {
			const date = new Date(2024, 0, 1);
			const result = DateHelpers.getNextWeekDates(date);
			expect(result[0]).toBe('2024-01-02');
		});

		it('should return dates in chronological order', () => {
			const date = new Date(2024, 0, 1);
			const result = DateHelpers.getNextWeekDates(date);
			for (let i = 1; i < result.length; i++) {
				const prev = result[i - 1];
				const curr = result[i];
				if (prev && curr) {
					expect(new Date(curr).getTime()).toBeGreaterThan(new Date(prev).getTime());
				}
			}
		});
	});
});

